    },
    eventEnd: function eventEnd() {
      this.inDungeons = false;
      this.dungeons = '';
      var b = this.findComponentDownward(this, 'dungeons');
      b.forcedToStopEvent();
      this.$store.commit("set_sys_info", {
        msg: "\n              \u624B\u52A8\u4E2D\u65AD\u4E86\u6311\u6218\n            ",
        type: 'warning'
      });
      setTimeout(function () {});
    },
    resetEndlessLv: function resetEndlessLv() {
      var _this5 = this;

      this.$message({
        message: '这将重置你的无尽等级，确认操作吗？',
        title: '提示',
        confirmBtnText: '重置',
        onClose: function onClose() {
          _this5.$store.commit("set_endless_lv", 1);

          _this5.closeDungeonsInfo();

          _this5.$store.commit("set_sys_info", {
            msg: "\n              \u65E0\u5C3D\u6311\u6218\u5C42\u6570\u91CD\u7F6E\u5230\u4E861\u7EA7\u3002\n            ",
            type: 'win'
          });
        }
      });
    },
    openMenuPanel: function openMenuPanel(type) {
      this.backpackPanelOpened = this.shopPanelOpened = false;

      switch (type) {
        case 'backpack':
          this.backpackPanelOpened = !this.backpackPanelOpened;
          break;

        case 'shop':
          this.shopPanelOpened = !this.shopPanelOpened;
          break;

        case 'rein':
          this.reinPanelOpened = !this.reinPanelOpened;
          break;

        default:
          break;
      }
    },
    closePanel: function closePanel() {
      this.backpackPanelOpened = this.shopPanelOpened = this.importSaveDataPanelOpened = this.exportSaveDataPanelOpened = this.strengthenEquipmentPanelOpened = this.reinPanelOpened = false;
      this.GMOpened = false;
      this.saveDateString = '';
      var equimentPanel = this.findComponentDownward(this, "equimentPanel");
      equimentPanel.stopAutoStreng();
    },
    initial: function initial() {
      var html = document.documentElement;
      var wW = html.clientHeight;
      var designSize = 1000; //设计高度

      if (!this.fullScreen) {
        wW = html.clientHeight;
      }

      var rem = wW * 100 / designSize;
      document.documentElement.style.fontSize = rem + "px";

      if (document.documentElement.clientWidth < 768) {
        this.$store.commit('set_operator_schema', true);
      } else {
        this.$store.commit('set_operator_schema', false);
      }
    },
    contextmenu: function contextmenu(e) {// 鼠标右键
    },
    showItemInfo: function showItemInfo(e, type, item, needComparison) {
      if (needComparison === false) {
        this.needComparison = false;
      } else {
        this.needComparison = true;
      }

      var x = e.pageX,
          y = e.pageY,
          maxH = window.innerHeight;

      if (y < window.innerHeight / 2) {
        this.itemDialogStyle = {
          display: 'flex',
          'top': y + 20 + 'px',
          'left': x + 20 + 'px'
        };
      } else {
        this.itemDialogStyle = {
          display: 'flex',
          'bottom': maxH - y + 20 + 'px',
          'left': x + 20 + 'px'
        };
      }

      switch (type) {
        case 'weapon':
          this.weapon = item;
          this.weaponShow = true;
          break;

        case 'armor':
          this.armor = item;
          this.armorShow = true;
          break;

        case 'ring':
          this.ring = item;
          this.ringShow = true;
          break;

        case 'neck':
          this.neck = item;
          this.neckShow = true;
          break;

        default:
          break;
      }
    },
    closeItemInfo: function closeItemInfo() {
      this.needComparison = true;
      this.weaponShow = this.armorShow = this.ringShow = this.neckShow = false;
    },
    setSysInfo: function setSysInfo() {
      this.$store.commit("set_sys_info", {
        msg: "\n              \u526F\u672C\u63A2\u7D22\u6210\u529F\uFF01\n            ",
        type: 'win'
      });
    }
  }
};
